INSERT INTO seed_node (node_key, parent_key, order_index, node_type, checkpoint_type, selection_type, required_count, title, description, reason, layout_role, layout_group, layout_rank, layout_order, estimated_hours, difficulty_level, priority, position_x, position_y, metadata, is_required, is_trackable, learning_outcomes, completion_criteria) VALUES
('ph-ml-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Machine Learning Foundations and Role Context', 'Understand what machine learning engineers build, where ML fits in software products, and how supervised, unsupervised, and production ML workflows connect.', 'This phase builds practical machine learning engineering capability for machine learning foundations and role context.', 'trunk', 'ph-ml-foundations', 1, 0, 22, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "visualRole": "trunk"}'::jsonb, true, false, '["Explain the purpose of the Machine Learning Foundations and Role Context phase and its role in the full machine learning engineering path.", "Connect the phase topics to concrete machine learning engineering deliverables.", "Identify the artifacts or evidence needed before progressing."]'::jsonb, '["Summarize the key concepts covered in Machine Learning Foundations and Role Context.", "Identify completed and incomplete child topics or projects.", "Prepare notes or artifacts that show readiness for the next phase."]'::jsonb),
('grp-ml-role-and-workflow', 'ph-ml-foundations', 1, 'choice_group', NULL, 'complete_all', 5, 'ML Role and Workflow', 'Group topics for ML Role and Workflow inside Machine Learning Foundations and Role Context.', 'This group organizes the core learning outcomes for ml role and workflow.', 'side', 'ph-ml-foundations', 1, 1, 9, 'beginner', 90, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "selectionType": "complete_all"}'::jsonb, true, false, '["Compare the options or grouped topics inside ML Role and Workflow.", "Select or complete the required children according to the group rule.", "Explain how the selected work supports practical machine learning engineering readiness."]'::jsonb, '["Complete the required number of child nodes for this group.", "Document why the selected options fit the learner''s target direction or project needs.", "Confirm that required child projects or topics have reviewable evidence."]'::jsonb),
('ml-engineer-role', 'grp-ml-role-and-workflow', 1, 'topic', NULL, NULL, NULL, 'Machine Learning Engineer Role', 'Understand the responsibilities of ML engineers and how they differ from data scientists, AI engineers, and researchers.', 'This item develops applied machine learning engineering ability in machine learning engineer role.', 'choice', 'grp-ml-role-and-workflow', 1, 1, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Machine Learning Engineer Role affects practical machine learning engineering work.", "Apply Machine Learning Engineer Role to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Machine Learning Engineer Role.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('ml-product-lifecycle', 'grp-ml-role-and-workflow', 2, 'topic', NULL, NULL, NULL, 'ML Product Lifecycle', 'Learn the path from problem framing and data collection to modeling, deployment, monitoring, and iteration.', 'This item develops applied machine learning engineering ability in ml product lifecycle.', 'choice', 'grp-ml-role-and-workflow', 1, 2, 4, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how ML Product Lifecycle affects practical machine learning engineering work.", "Apply ML Product Lifecycle to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of ML Product Lifecycle.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('supervised-unsupervised-rl-overview', 'grp-ml-role-and-workflow', 3, 'topic', NULL, NULL, NULL, 'Supervised, Unsupervised, and Reinforcement Learning Overview', 'Compare major learning paradigms and understand when each is useful.', 'This item develops applied machine learning engineering ability in supervised, unsupervised, and reinforcement learning overview.', 'choice', 'grp-ml-role-and-workflow', 1, 3, 4, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Supervised, Unsupervised, and Reinforcement Learning Overview affects practical machine learning engineering work.", "Apply Supervised, Unsupervised, and Reinforcement Learning Overview to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Supervised, Unsupervised, and Reinforcement Learning Overview.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('ml-problem-framing', 'grp-ml-role-and-workflow', 4, 'topic', NULL, NULL, NULL, 'ML Problem Framing', 'Translate business or product goals into measurable ML tasks, metrics, baselines, and constraints.', 'This item develops applied machine learning engineering ability in ml problem framing.', 'choice', 'grp-ml-role-and-workflow', 1, 4, 4, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how ML Problem Framing affects practical machine learning engineering work.", "Apply ML Problem Framing to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of ML Problem Framing.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('baseline-first-thinking', 'grp-ml-role-and-workflow', 5, 'topic', NULL, NULL, NULL, 'Baseline-First Thinking', 'Learn why simple baselines, heuristics, and non-ML solutions are critical before building complex models.', 'This item develops applied machine learning engineering ability in baseline-first thinking.', 'choice', 'grp-ml-role-and-workflow', 1, 5, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Baseline-First Thinking affects practical machine learning engineering work.", "Apply Baseline-First Thinking to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Baseline-First Thinking.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('grp-core-tooling', 'ph-ml-foundations', 2, 'choice_group', NULL, 'complete_all', 5, 'Core Tooling', 'Group topics for Core Tooling inside Machine Learning Foundations and Role Context.', 'This group organizes the core learning outcomes for core tooling.', 'side', 'ph-ml-foundations', 1, 2, 8, 'beginner', 90, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "selectionType": "complete_all"}'::jsonb, true, false, '["Compare the options or grouped topics inside Core Tooling.", "Select or complete the required children according to the group rule.", "Explain how the selected work supports practical machine learning engineering readiness."]'::jsonb, '["Complete the required number of child nodes for this group.", "Document why the selected options fit the learner''s target direction or project needs.", "Confirm that required child projects or topics have reviewable evidence."]'::jsonb),
('python-environment-management', 'grp-core-tooling', 1, 'topic', NULL, NULL, NULL, 'Python Environment Management', 'Use virtual environments, package managers, notebooks, and reproducible local ML setups.', 'This item develops applied machine learning engineering ability in python environment management.', 'choice', 'grp-core-tooling', 1, 1, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Python Environment Management affects practical machine learning engineering work.", "Apply Python Environment Management to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Python Environment Management.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('git-for-ml-projects', 'grp-core-tooling', 2, 'topic', NULL, NULL, NULL, 'Git for ML Projects', 'Use Git branches, commits, pull requests, and experiment-friendly repository organization.', 'This item develops applied machine learning engineering ability in git for ml projects.', 'choice', 'grp-core-tooling', 1, 2, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Git for ML Projects affects practical machine learning engineering work.", "Apply Git for ML Projects to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Git for ML Projects.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('linux-shell-for-ml', 'grp-core-tooling', 3, 'topic', NULL, NULL, NULL, 'Linux Shell for ML', 'Use shell commands for files, processes, remote machines, logs, and basic automation.', 'This item develops applied machine learning engineering ability in linux shell for ml.', 'choice', 'grp-core-tooling', 1, 3, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Linux Shell for ML affects practical machine learning engineering work.", "Apply Linux Shell for ML to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Linux Shell for ML.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('jupyter-notebooks', 'grp-core-tooling', 4, 'topic', NULL, NULL, NULL, 'Jupyter Notebooks', 'Use notebooks for exploration while keeping analysis reproducible and maintainable.', 'This item develops applied machine learning engineering ability in jupyter notebooks.', 'choice', 'grp-core-tooling', 1, 4, 3, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how Jupyter Notebooks affects practical machine learning engineering work.", "Apply Jupyter Notebooks to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Jupyter Notebooks.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('ml-project-structure', 'grp-core-tooling', 5, 'topic', NULL, NULL, NULL, 'ML Project Structure', 'Organize ML code, configs, data references, notebooks, tests, and documentation.', 'This item develops applied machine learning engineering ability in ml project structure.', 'choice', 'grp-core-tooling', 1, 5, 4, 'beginner', 80, NULL, NULL, '{"source": "roadmap.sh/machine-learning"}'::jsonb, true, true, '["Explain how ML Project Structure affects practical machine learning engineering work.", "Apply ML Project Structure to run ML experiments or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of ML Project Structure.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('chk-ml-foundations-review', 'ph-ml-foundations', 90, 'checkpoint', 'gate', NULL, NULL, 'ML Foundations Review Gate', 'Review checkpoint for Machine Learning Foundations and Role Context. The learner consolidates evidence from Machine Learning Engineer Role, ML Product Lifecycle, Supervised, Unsupervised, and Reinforcement Learning Overview, ML Problem Framing, identifies unresolved prerequisite gaps, and decides whether to continue, review selected topics, or complete extra practice before the next roadmap segment.', 'This checkpoint acts as a transition gate for the machine learning engineering roadmap. It supports reflection and planning; it is not a certification, mastery test, or claim of job readiness.', 'checkpoint', 'ph-ml-foundations', 1, 90, 2, 'beginner', 95, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "checkpointType": "review", "checkpointPurpose": "phase_review", "reviewMode": "gate", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Summarize the main concepts and decisions from Machine Learning Foundations and Role Context in practical machine learning engineering terms.", "Identify prerequisite gaps, unclear topics, or risks that should be reviewed before moving forward.", "Create a short evidence artifact that links completed roadmap items to what was learned."]'::jsonb, '["List the roadmap items reviewed for this checkpoint.", "Provide one evidence artifact such as notes, a diagram, a lab result, code, queries, screenshots, or a project review.", "Record at least two gaps, risks, or follow-up actions, or explicitly state that no critical gaps were found.", "Use the result to choose one next step: continue, review selected topics, or complete extra practice."]'::jsonb),
('proj-ml-environment-setup', 'ph-ml-foundations', 101, 'project', NULL, NULL, NULL, 'Required Reproducible ML Environment Setup', 'Create a reproducible Python ML workspace with Git, notebooks, dependency files, and a documented project layout.', 'Hands-on projects turn knowledge into portfolio evidence.', 'side', 'ph-ml-foundations', 1, 101, 5, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "projectType": "milestone"}'::jsonb, true, true, '["Build a working artifact that demonstrates Required Reproducible ML Environment Setup.", "Explain the main technical decisions and trade-offs behind the implementation.", "Document setup, validation steps, and known limitations."]'::jsonb, '["Demonstrate practical understanding of Required Reproducible ML Environment Setup.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('proj-ml-problem-framing-brief', 'ph-ml-foundations', 102, 'project', NULL, NULL, NULL, 'Optional ML Problem Framing Brief', 'Write a short product-style ML problem framing document with baseline, metric, data, and risk assumptions.', 'Hands-on projects turn knowledge into portfolio evidence.', 'side', 'ph-ml-foundations', 1, 102, 3, 'beginner', 60, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "projectType": "mini_project"}'::jsonb, false, true, '["Build a working artifact that demonstrates Optional ML Problem Framing Brief.", "Explain the main technical decisions and trade-offs behind the implementation.", "Document setup, validation steps, and known limitations."]'::jsonb, '["Demonstrate practical understanding of Optional ML Problem Framing Brief.", "Document decisions, evidence, risks, and next steps."]'::jsonb),
('ph-python-data-foundations', NULL, 2, 'phase', NULL, NULL, NULL, 'Python, Data, and Numerical Computing', 'Build the Python, data manipulation, numerical computing, and visualization skills needed for reliable ML experimentation.', 'This phase builds practical machine learning engineering capability for python, data, and numerical computing.', 'trunk', 'ph-python-data-foundations', 2, 0, 34, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/machine-learning", "visualRole": "trunk"}'::jsonb, true, false, '["Explain the purpose of the Python, Data, and Numerical Computing phase and its role in the full machine learning engineering path.", "Connect the phase topics to concrete machine learning engineering deliverables.", "Identify the artifacts or evidence needed before progressing."]'::jsonb, '["Summarize the key concepts covered in Python, Data, and Numerical Computing.", "Identify completed and incomplete child topics or projects.", "Prepare notes or artifacts that show readiness for the next phase."]'::jsonb),
